from __future__ import annotations

from pathlib import Path
import json
from typing import Any

from differential.backend_list import (
    BACKEND_CONFIG_DEFAULT_KEYS,
    BACKEND_CONFIG_TOP_LEVEL_KEYS,
    BACKEND_REQUIRED_CONFIG_KEYS,
)
from differential.result_contract import get_error_decision_table
from feature.feature_schema import FEATURE_REQUIRED_KEYS
from generate.testcase_bundle import get_testcase_bundle_contract

FEATURE_DATASET_TOP_LEVEL_KEYS = (
    "schema_version",
    "features",
    "feature_index",
    "feature_graph",
    "source_summary",
    "build_info",
)

FEATURE_INDEX_REQUIRED_KEYS = ("by_id", "by_category", "by_source")
FEATURE_GRAPH_ENTRY_KEYS = ("requires", "conflicts", "co_occurs", "rarity_score")
SOURCE_SUMMARY_KEYS = ("total_features", "by_source")
BUILD_INFO_KEYS = ("built_at", "builder", "source_revision")

SOURCE_BUNDLE_TOP_LEVEL_KEYS = (
    "source",
    "total_features",
    "features",
    "feature_graph",
    "build_info",
)


def load_json_compatible_mapping(path: Path) -> dict[str, Any]:

    try:
        data = json.loads(path.read_text())
    except json.JSONDecodeError as exc:
        raise ValueError(f"{path} must contain JSON-compatible text") from exc
    if not isinstance(data, dict):
        raise ValueError(f"{path} must decode to an object")
    return data


def _require_mapping(name: str, value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        raise ValueError(f"{name} must be an object")
    return value


def _require_string_list(name: str, value: Any) -> list[str]:
    if not isinstance(value, list) or not all(isinstance(item, str) for item in value):
        raise ValueError(f"{name} must be a list[str]")
    return value


def validate_feature_dataset(data: Any) -> dict[str, Any]:
    payload = _require_mapping("feature_dataset", data)
    if set(payload) != set(FEATURE_DATASET_TOP_LEVEL_KEYS):
        raise ValueError(
            "feature_dataset top-level keys must be exactly "
            f"{FEATURE_DATASET_TOP_LEVEL_KEYS}"
        )
    if payload["schema_version"] != 1:
        raise ValueError("feature_dataset schema_version must be 1")

    features = payload["features"]
    if not isinstance(features, list) or not features:
        raise ValueError("feature_dataset features must be a non-empty list")
    feature_ids: list[str] = []
    for index, feature in enumerate(features):
        feature_map = _require_mapping(f"features[{index}]", feature)
        if set(feature_map) != set(FEATURE_REQUIRED_KEYS):
            raise ValueError(
                f"features[{index}] keys must be exactly {FEATURE_REQUIRED_KEYS}"
            )
        if not all(
            isinstance(feature_map[key], str) for key in FEATURE_REQUIRED_KEYS[:5]
        ):
            raise ValueError(f"features[{index}] string fields must be strings")
        _require_string_list(f"features[{index}].tags", feature_map["tags"])
        _require_mapping(f"features[{index}].metadata", feature_map["metadata"])
        feature_ids.append(feature_map["feature_id"])

    if len(set(feature_ids)) != len(feature_ids):
        raise ValueError("feature_id values must be unique")

    feature_index = _require_mapping("feature_index", payload["feature_index"])
    if set(feature_index) != set(FEATURE_INDEX_REQUIRED_KEYS):
        raise ValueError(
            f"feature_index keys must be exactly {FEATURE_INDEX_REQUIRED_KEYS}"
        )
    by_id = _require_mapping("feature_index.by_id", feature_index["by_id"])
    if set(by_id) != set(feature_ids):
        raise ValueError("feature_index.by_id keys must match feature IDs")
    if not all(isinstance(value, int) for value in by_id.values()):
        raise ValueError("feature_index.by_id values must be int indices")
    for index_name in ("by_category", "by_source"):
        group_index = _require_mapping(
            f"feature_index.{index_name}", feature_index[index_name]
        )
        for group_name, members in group_index.items():
            if not isinstance(group_name, str):
                raise ValueError(f"feature_index.{index_name} keys must be strings")
            _require_string_list(f"feature_index.{index_name}.{group_name}", members)

    feature_graph = _require_mapping("feature_graph", payload["feature_graph"])
    for feature_id, entry in feature_graph.items():
        if feature_id not in feature_ids:
            raise ValueError(f"feature_graph contains unknown feature_id {feature_id}")
        entry_map = _require_mapping(f"feature_graph.{feature_id}", entry)
        if set(entry_map) != set(FEATURE_GRAPH_ENTRY_KEYS):
            raise ValueError(
                f"feature_graph.{feature_id} keys must be exactly {FEATURE_GRAPH_ENTRY_KEYS}"
            )
        for key in ("requires", "conflicts", "co_occurs"):
            _require_string_list(f"feature_graph.{feature_id}.{key}", entry_map[key])
        if not isinstance(entry_map["rarity_score"], (int, float)):
            raise ValueError(f"feature_graph.{feature_id}.rarity_score must be numeric")

    source_summary = _require_mapping("source_summary", payload["source_summary"])
    if set(source_summary) != set(SOURCE_SUMMARY_KEYS):
        raise ValueError(f"source_summary keys must be exactly {SOURCE_SUMMARY_KEYS}")
    if source_summary["total_features"] != len(features):
        raise ValueError("source_summary.total_features must match features length")
    by_source = _require_mapping(
        "source_summary.by_source", source_summary["by_source"]
    )
    if not all(
        isinstance(key, str) and isinstance(value, int)
        for key, value in by_source.items()
    ):
        raise ValueError("source_summary.by_source must map source names to int counts")

    build_info = _require_mapping("build_info", payload["build_info"])
    if set(build_info) != set(BUILD_INFO_KEYS):
        raise ValueError(f"build_info keys must be exactly {BUILD_INFO_KEYS}")
    if not all(isinstance(build_info[key], str) for key in BUILD_INFO_KEYS):
        raise ValueError("build_info values must be strings")

    return payload


def validate_source_bundle(data: Any) -> dict[str, Any]:
    payload = _require_mapping("source_bundle", data)
    if set(payload) != set(SOURCE_BUNDLE_TOP_LEVEL_KEYS):
        raise ValueError(
            "source_bundle top-level keys must be exactly "
            f"{SOURCE_BUNDLE_TOP_LEVEL_KEYS}"
        )
    if not isinstance(payload["source"], str) or not payload["source"]:
        raise ValueError("source_bundle.source must be a non-empty string")

    features = payload["features"]
    if not isinstance(features, list):
        raise ValueError("source_bundle.features must be a list")

    if not isinstance(payload["total_features"], int):
        raise ValueError("source_bundle.total_features must be an int")
    if payload["total_features"] != len(features):
        raise ValueError("source_bundle.total_features must match features length")

    feature_ids: list[str] = []
    for index, feature in enumerate(features):
        feature_map = _require_mapping(f"features[{index}]", feature)
        if set(feature_map) != set(FEATURE_REQUIRED_KEYS):
            raise ValueError(
                f"features[{index}] keys must be exactly {FEATURE_REQUIRED_KEYS}"
            )
        if not all(
            isinstance(feature_map[key], str) for key in FEATURE_REQUIRED_KEYS[:5]
        ):
            raise ValueError(f"features[{index}] string fields must be strings")
        _require_string_list(f"features[{index}].tags", feature_map["tags"])
        _require_mapping(f"features[{index}].metadata", feature_map["metadata"])
        feature_ids.append(feature_map["feature_id"])

    if len(set(feature_ids)) != len(feature_ids):
        raise ValueError("feature_id values must be unique")

    feature_graph = _require_mapping("feature_graph", payload["feature_graph"])
    for feature_id, entry in feature_graph.items():
        entry_map = _require_mapping(f"feature_graph.{feature_id}", entry)
        if set(entry_map) != set(FEATURE_GRAPH_ENTRY_KEYS):
            raise ValueError(
                f"feature_graph.{feature_id} keys must be exactly "
                f"{FEATURE_GRAPH_ENTRY_KEYS}"
            )
        for key in ("requires", "conflicts", "co_occurs"):
            _require_string_list(f"feature_graph.{feature_id}.{key}", entry_map[key])
        if not isinstance(entry_map["rarity_score"], (int, float)):
            raise ValueError(
                f"feature_graph.{feature_id}.rarity_score must be numeric"
            )

    _require_mapping("build_info", payload["build_info"])

    return payload


def validate_backend_config(data: Any) -> dict[str, Any]:
    payload = _require_mapping("backend_config", data)
    if set(payload) != set(BACKEND_CONFIG_TOP_LEVEL_KEYS):
        raise ValueError(
            "backend_config top-level keys must be exactly "
            f"{BACKEND_CONFIG_TOP_LEVEL_KEYS}"
        )
    if payload["schema_version"] != 1:
        raise ValueError("backend_config schema_version must be 1")

    defaults = _require_mapping("defaults", payload["defaults"])
    missing_defaults = [
        key for key in BACKEND_CONFIG_DEFAULT_KEYS if key not in defaults
    ]
    if missing_defaults:
        raise ValueError(f"backend defaults missing keys: {missing_defaults}")
    if (
        not isinstance(defaults["compile_timeout_sec"], int)
        or defaults["compile_timeout_sec"] <= 0
    ):
        raise ValueError("defaults.compile_timeout_sec must be a positive int")
    if (
        not isinstance(defaults["simulate_timeout_sec"], int)
        or defaults["simulate_timeout_sec"] <= 0
    ):
        raise ValueError("defaults.simulate_timeout_sec must be a positive int")
    if not isinstance(defaults["runtime_enabled"], bool):
        raise ValueError("defaults.runtime_enabled must be a bool")
    if defaults["coverage_mode"] != "edge":
        raise ValueError("defaults.coverage_mode must be 'edge'")
    if (
        not isinstance(defaults["llvm_profdata_binary"], str)
        or not defaults["llvm_profdata_binary"].strip()
    ):
        raise ValueError("defaults.llvm_profdata_binary must be a non-empty string")

    backends = _require_mapping("backends", payload["backends"])
    if not backends:
        raise ValueError("backends must not be empty")
    for backend_name, backend_cfg in backends.items():
        if not isinstance(backend_name, str):
            raise ValueError("backend names must be strings")
        if backend_name not in BACKEND_REQUIRED_CONFIG_KEYS:
            raise ValueError(
                f"unsupported backend key in backend config: {backend_name}"
            )
        backend_map = _require_mapping(f"backends.{backend_name}", backend_cfg)
        required_keys = BACKEND_REQUIRED_CONFIG_KEYS[backend_name]
        unexpected_keys = sorted(key for key in backend_map if key not in required_keys)
        if unexpected_keys:
            raise ValueError(
                f"backends.{backend_name} contains unsupported keys: {unexpected_keys}"
            )
        missing_keys = [key for key in required_keys if key not in backend_map]
        if missing_keys:
            raise ValueError(f"backends.{backend_name} missing keys: {missing_keys}")
        for key in required_keys:
            if not isinstance(backend_map[key], str) or not backend_map[key].strip():
                raise ValueError(
                    f"backends.{backend_name}.{key} must be a non-empty string"
                )
            if not Path(backend_map[key]).is_absolute():
                raise ValueError(
                    f"backends.{backend_name}.{key} must be an absolute path"
                )

    return payload


def contract_snapshot() -> dict[str, Any]:
    return {
        "feature_dataset_top_level_keys": list(FEATURE_DATASET_TOP_LEVEL_KEYS),
        "backend_config_top_level_keys": list(BACKEND_CONFIG_TOP_LEVEL_KEYS),
        "testcase_bundle_contract": get_testcase_bundle_contract(),
        "error_decision_table": get_error_decision_table(),
    }

from __future__ import annotations

from dataclasses import dataclass
from typing import cast
from typing import Any

FEATURE_REQUIRED_KEYS = (
    "feature_id",
    "name",
    "category",
    "description",
    "source",
    "tags",
    "metadata",
)


@dataclass(frozen=True)
class Feature:
    feature_id: str
    name: str
    category: str
    description: str
    source: str
    tags: list[str]
    metadata: dict[str, Any]


def _require_mapping(name: str, value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        raise ValueError(f"{name} must be an object")
    return cast(dict[str, Any], value)


def _require_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value:
        raise ValueError(f"{name} must be a non-empty string")
    return value


def _require_string_list(name: str, value: Any) -> list[str]:
    if not isinstance(value, list) or not all(isinstance(item, str) for item in value):
        raise ValueError(f"{name} must be a list[str]")
    return list(value)


def feature_from_dict(data: dict[str, Any]) -> Feature:
    payload = _require_mapping("feature", data)
    if set(payload) != set(FEATURE_REQUIRED_KEYS):
        raise ValueError(f"feature keys must be exactly {FEATURE_REQUIRED_KEYS}")

    metadata = _require_mapping("feature.metadata", payload["metadata"])
    return Feature(
        feature_id=_require_string("feature.feature_id", payload["feature_id"]),
        name=_require_string("feature.name", payload["name"]),
        category=_require_string("feature.category", payload["category"]),
        description=_require_string("feature.description", payload["description"]),
        source=_require_string("feature.source", payload["source"]),
        tags=_require_string_list("feature.tags", payload["tags"]),
        metadata=dict(metadata),
    )


def feature_to_dict(feature: Feature) -> dict[str, Any]:
    return {
        "feature_id": feature.feature_id,
        "name": feature.name,
        "category": feature.category,
        "description": feature.description,
        "source": feature.source,
        "tags": list(feature.tags),
        "metadata": dict(feature.metadata),
    }
